INSERT INTO public.ai_models (id, title, description, category, provider, pricing_base, pricing_type, pricing_desc, variables_schema, is_active) VALUES 
('fal-ai/nano-banana-2/edit', 'Nano Banana 2', 'Nano Banana 2 is Google''s new state-of-the-art image generation and editing model
', 'image-to-image', 'fal-ai', 0.08, 'fixed_inferred', 'Your request will cost **$0.08** per image. For **$1.00**, you can run this model **12** times. 2K and 4K outputs will be charged at **1.5** times and **2** times the standard rate, respectively. 0.5K (512px) resolution outputs will be charged at **0.75** times the standard rate. If web search is used, an additional $0.015 will be charged. If high thinking is used, an additional $0.002 will be charged. **Note: Pricing is subject to change.**', '[{"key":"aspect_ratio","label":"Aspect Ratio","default":"16:9","options":["16:9","9:16","1:1","4:3","3:4"]}]'::jsonb, true),
('fal-ai/nano-banana-pro/edit', 'Nano Banana Pro', 'Nano Banana Pro is Google''s new state-of-the-art image generation and editing model', 'image-to-image', 'fal-ai', 0.15, 'fixed_inferred', 'Your request will cost **$0.15** per image. For **$1.00**, you can run this model **7** times. 4K outputs will be charged at double the standard rate. If web search is used, an additional $0.015 will be charged. Note: Pricing may change in the future.', '[{"key":"aspect_ratio","label":"Aspect Ratio","default":"16:9","options":["16:9","9:16","1:1","4:3","3:4"]}]'::jsonb, true),
('fal-ai/nano-banana-2', 'Nano Banana 2', 'Nano Banana 2 is Google''s new state-of-the-art fast image generation and editing model', 'text-to-image', 'fal-ai', 0.08, 'fixed_inferred', 'Your request will cost **$0.08** per image. For **$1.00**, you can run this model **12** times. 2K and 4K outputs will be charged at **1.5** times and **2** times the standard rate, respectively. 0.5K (512px) resolution outputs will be charged at **0.75** times the standard rate. If web search is used, an additional $0.015 will be charged. If high thinking is used, an additional $0.002 will be charged. **Note: Pricing is subject to change.**', '[{"key":"aspect_ratio","label":"Aspect Ratio","default":"16:9","options":["16:9","9:16","1:1","4:3","3:4"]}]'::jsonb, true),
