('fal-ai/kling-video/v3/pro/image-to-video', 'Kling Video v3 Image to Video [Pro]', 'Kling 3.0 Pro: Top-tier image-to-video with cinematic visuals, fluid motion, and native audio generation, with custom element support.', 'image-to-video', 'fal-ai', 0.112, 'fixed_inferred', 'For every second of video you generated, you will be charged **$0.112** (audio off) or **$0.168** (audio on), if voice control is used while generating audio you will be charged **$0.196**. For example, a 5s video with audio on and voice control will cost **$0.98**', '[{"key":"duration","label":"Duration (s)","default":"5","options":["5","10","15"]},{"key":"resolution","label":"Resolution","default":"1080p","options":["720p","1080p"]}]'::jsonb, true),
('fal-ai/nano-banana/edit', 'Nano Banana', 'Google''s famous original image generation and editing model', 'image-to-image', 'fal-ai', 0.0016, 'fixed', 'Your request will cost **$0.039** per image. For **$1.00**, you can run this model **25 times.**', '[{"key":"aspect_ratio","label":"Aspect Ratio","default":"16:9","options":["16:9","9:16","1:1","4:3","3:4"]}]'::jsonb, true),
