('fal-ai/flux-2-pro', 'Flux 2 Pro', 'Image editing with FLUX.2 [pro] from Black Forest Labs. Ideal for high-quality image manipulation, style transfer, and sequential editing workflows', 'text-to-image', 'fal-ai', 0.03, 'fixed_inferred', 'Your request will cost **$0.03** for the first megapixel of output, plus **$0.015** per extra megapixel of input and output, rounded up to the nearest megapixel. For example, a **1024x1024** image will cost **$0.03**, and a **1920x1080** image will cost **$0.045** (**$0.03** for first megapixel + **$0.015** for the second megapixel). Similarly, a **512x512** output will cost **$0.03** (**$0.03** for **0.25** megapixels, rounded to **1** megapixel)', '[{"key":"aspect_ratio","label":"Aspect Ratio","default":"16:9","options":["16:9","9:16","1:1","4:3","3:4"]}]'::jsonb, true),
('bytedance/seedance-2.0/image-to-video', 'Seedance 2 Image to Video', 'ByteDance''s most advanced image-to-video model. Animate still images into cinematic video with synchronized audio, start and end frame control, and motion prompts.', 'image-to-video', 'fal-ai', 0.3024, 'duration_sec', 'For every second of 720p video you generated, you will be charged **$0.3024/second**. Your request will cost $0.014 per 1000 tokens. The number of tokens is given by (height of output video * width of output video * duration * 24) / 1024. ', '[{"key":"image_size","label":"Image Size","default":"landscape_16_9","options":["landscape_16_9","portrait_4_3","square"]}]'::jsonb, true),
('fal-ai/flux-pro/v1.1', 'FLUX1.1 [pro]', 'FLUX1.1 [pro] is an enhanced version of FLUX.1 [pro], improved image generation capabilities, delivering superior composition, detail, and artistic fidelity compared to its predecessor.', 'text-to-image', 'fal-ai', 0, 'unknown', '', '[{"key":"aspect_ratio","label":"Aspect Ratio","default":"16:9","options":["16:9","9:16","1:1","4:3","3:4"]}]'::jsonb, true),
('xai/grok-imagine-image/edit', 'Grok Imagine Image', 'Edit images precisely with xAI''s Grok Imagine model', 'image-to-image', 'fal-ai', 0.022, 'fixed_inferred', 'Your request will cost **$0.022** per image (**$0.02** for image output + **$0.002** for image input).', '[]'::jsonb, true),
('fal-ai/flux-pro/kontext', 'FLUX.1 Kontext [pro]', 'FLUX.1 Kontext [pro] handles both text and reference images as inputs, seamlessly enabling targeted, local edits and complex transformations of entire scenes.', 'image-to-image', 'fal-ai', 0, 'unknown', '', '[{"key":"aspect_ratio","label":"Aspect Ratio","default":"16:9","options":["16:9","9:16","1:1","4:3","3:4"]}]'::jsonb, true),
('fal-ai/gpt-image-1.5/edit', 'GPT-Image 1.5', 'GPT Image 1.5 generates high-fidelity images with strong prompt adherence, preserving composition, lighting, and fine-grained detail.', 'image-to-image', 'fal-ai', 0, 'tokens', 'Your request will cost different amounts based on the number of images, quality, and size.

- You will be charged $0.005 per 1,000 input text tokens. One word is roughly 4 tokens.
- You will be charged $0.008 per 1,000 input image tokens. One 1024x1024 image is roughly 135 tokens in low fidelity mode, or 3,050 tokens in high fidelity mode.
-  You will be charged $0.010 per 1,000 output text tokens. The model will consume tokens reasoning about your prompt based on it''s complexity.
- For **low** quality, you will be charged $0.009 for 1024x1024 or $0.013 for any other size *per image*. 
- For **medium** quality, you will be charged $0.034 for 1024x1024, $0.051 for 1024x1536 and $0.050 for 1536x1024 *per image*.
- For **high** quality, you will be charged $0.133 for 1024x1024, $0.200 for 1024x1536 or $0.199 for 1536x1024 *per image*.', '[{"key":"image_size","label":"Image Size","default":"landscape_16_9","options":["landscape_16_9","portrait_4_3","square"]}]'::jsonb, true),
('fal-ai/flux-2-pro/edit', 'Flux 2 Pro', 'Text-to-image generation with FLUX.2 [pro] from Black Forest Labs. Optimized for maximum quality, exceptional photorealism and artistic images.', 'image-to-image', 'fal-ai', 0.03, 'fixed_inferred', 'Your request will cost **$0.03** for the first megapixel of output, plus **$0.015** per extra megapixel of input and output, rounded up to the nearest megapixel. For example, a **1024x1024** image will cost **$0.03**, and a **1920x1080** image will cost **$0.045** (**$0.03** for first megapixel + **$0.015** for the second megapixel). Similarly, a **512x512** output will cost **$0.03** (**$0.03** for**0.25** megapixels, rounded to **1** megapixel)', '[{"key":"aspect_ratio","label":"Aspect Ratio","default":"16:9","options":["16:9","9:16","1:1","4:3","3:4"]}]'::jsonb, true),
('bytedance/seedance-2.0/reference-to-video', 'Seedance 2 Reference to Video', 'ByteDance''s most advanced reference-to-video model. Generate video from up to 9 images, 3 videos, and 3 audio clips with native audio and cinematic camera control.', 'image-to-video', 'fal-ai', 0.3024, 'duration_sec', 'For every second of 720p video you generated, you will be charged **$0.3024/second**. Your request will cost $0.014 per 1000 tokens. The number of tokens is given by (height of output video * width of output video * ( input duration + output duration) * 24) / 1024. **If video inputs are provided the price is multiplied by 0.6**. With video inputs and 720p resolution the price is **$0.1814** per second.', '[{"key":"image_size","label":"Image Size","default":"landscape_16_9","options":["landscape_16_9","portrait_4_3","square"]}]'::jsonb, true),
('fal-ai/nano-banana', 'Nano Banana', 'Google''s famous original image generation and editing model', 'text-to-image', 'fal-ai', 0.0016, 'fixed', 'Your request will cost **$0.039** per image. For **$1.00**, you can run this model **25 times.**', '[{"key":"aspect_ratio","label":"Aspect Ratio","default":"16:9","options":["16:9","9:16","1:1","4:3","3:4"]}]'::jsonb, true),
('fal-ai/kling-video/v2.6/pro/image-to-video', 'Kling Video v2.6 Image to Video', 'Kling 2.6 Pro: Top-tier image-to-video with cinematic visuals, fluid motion, and native audio generation.', 'image-to-video', 'fal-ai', 0.07, 'duration_sec', 'Videos generated without audio cost $0.07 per second. Videos with native audio cost $0.14 per second, and videos with native audio and voice control cost $0.168 per second. For example, a 5-second video with audio costs $0.70, while a 10-second video with audio and voice control costs $1.68', '[{"key":"duration","label":"Duration (s)","default":"5","options":["5","10","15"]},{"key":"resolution","label":"Resolution","default":"1080p","options":["720p","1080p"]}]'::jsonb, true),
('fal-ai/flux-lora', 'FLUX.1 [dev] with LoRAs', 'Super fast endpoint for the FLUX.1 [dev] model with LoRA support, enabling rapid and high-quality image generation using pre-trained LoRA adaptations for personalization, specific styles, brand identities, and product-specific outputs.', 'text-to-image', 'fal-ai', 0, 'unknown', '', '[{"key":"aspect_ratio","label":"Aspect Ratio","default":"16:9","options":["16:9","9:16","1:1","4:3","3:4"]}]'::jsonb, true),
('xai/grok-imagine-video/image-to-video', 'Grok Imagine Video', 'Generate videos from images with audio using xAI''s Grok Imagine Video model. ', 'image-to-video', 'fal-ai', 0.05, 'duration_sec', 'A 6s 480p video will cost **$0.302** (**$0.05** per second of 480p video + **$0.002** for image input). At an output resolution of 480p, every second costs **$0.05**, and at 720p, every second costs **$0.07**.', '[{"key":"duration","label":"Duration (s)","default":"5","options":["5","10","15"]},{"key":"resolution","label":"Resolution","default":"1080p","options":["720p","1080p"]}]'::jsonb, true),
